"""
Model selection system for automatic and manual model choosing.
Provides safe fallbacks and resource-aware model selection.
"""
import asyncio
import logging
from typing import Optional, List, Dict, Any
from dataclasses import dataclass
from .config import Config
from .runtime_profiles import ResourceProfile, resource_manager

logger = logging.getLogger(__name__)

@dataclass
class ModelInfo:
    """Information about an available model"""
    name: str
    size_category: str  # "tiny", "small", "medium", "large", "xlarge"
    estimated_ram_gb: float
    context_length: int
    specialization: List[str]  # ["code", "chat", "reasoning", "long_context"]
    quantization: Optional[str] = None  # "Q4_K_M", "Q8_0", etc.
    is_available: bool = False

class ModelSelector:
    """
    Intelligent model selection based on task type and resource constraints.
    Provides safe fallbacks and resource-aware recommendations.
    """

    # Model database with estimated requirements
    MODEL_DATABASE = {
        "gemma2:2b-16k": ModelInfo(
            name="gemma2:2b-16k",
            size_category="small",
            estimated_ram_gb=2.5,
            context_length=16384,
            specialization=["chat", "code"],
            quantization="Q4_K_M"
        ),
        "gemma2:9b": ModelInfo(
            name="gemma2:9b",
            size_category="medium",
            estimated_ram_gb=6.0,
            context_length=8192,
            specialization=["chat", "reasoning"],
            quantization="Q4_K_M"
        ),
        "gemma_coder_9b": ModelInfo(
            name="gemma_coder_9b",
            size_category="medium",
            estimated_ram_gb=6.5,
            context_length=8192,
            specialization=["code"],
            quantization="Q4_K_M"
        ),
        "deepseek-coder:6.7b": ModelInfo(
            name="deepseek-coder:6.7b",
            size_category="medium",
            estimated_ram_gb=5.5,
            context_length=4096,
            specialization=["code"],
            quantization="Q4_K_M"
        ),
        "llama3.2:3b": ModelInfo(
            name="llama3.2:3b",
            size_category="small",
            estimated_ram_gb=3.0,
            context_length=8192,
            specialization=["chat", "reasoning"],
            quantization="Q4_K_M"
        ),
        "codellama:7b-code": ModelInfo(
            name="codellama:7b-code",
            size_category="medium",
            estimated_ram_gb=5.0,
            context_length=4096,
            specialization=["code"],
            quantization="Q4_K_M"
        )
    }

    def __init__(self, config: Config, ollama_client=None):
        self.config = config
        self.ollama_client = ollama_client
        self.available_models: List[str] = []
        self.last_known_good: Optional[str] = None
        self.warmup_cache: Dict[str, bool] = {}

    async def refresh_available_models(self) -> List[str]:
        """Refresh list of available models from Ollama"""
        if not self.ollama_client:
            return []

        try:
            # This would call the Ollama API to list models
            # For now, we'll simulate based on common models
            response = await self.ollama_client.client.get(f"{self.ollama_client.base_url}/api/tags")
            if response.status_code == 200:
                models_data = response.json()
                self.available_models = [model['name'] for model in models_data.get('models', [])]
            else:
                logger.warning(f"Failed to fetch models: {response.status_code}")
                self.available_models = []
        except Exception as e:
            logger.error(f"Error fetching available models: {e}")
            self.available_models = []

        # Update availability in database
        for model_name in self.MODEL_DATABASE:
            self.MODEL_DATABASE[model_name].is_available = model_name in self.available_models

        return self.available_models

    def get_safe_fallback(self) -> str:
        """Get the safest fallback model"""
        return self.config.runtime.fallback_model

    def select_model_for_task(self, task_type: str, resource_profile: ResourceProfile) -> str:
        """
        Select appropriate model for task type and resource constraints.

        Args:
            task_type: "code", "chat", "reasoning", "long_context", "standard"
            resource_profile: Current resource constraints

        Returns:
            Selected model name
        """
        # If auto-detect is disabled, use preferred model
        if not self.config.runtime.auto_detect:
            return self.config.model.name

        # Get memory constraint from profile
        memory_limit_gb = resource_profile.memory_limit_mb / 1024 if resource_profile.memory_limit_mb else float('inf')

        # Find suitable models for task and resources
        suitable_models = []

        for model_name, model_info in self.MODEL_DATABASE.items():
            # Check if model fits in memory budget
            if model_info.estimated_ram_gb > memory_limit_gb:
                continue

            # Check if model is available
            if not model_info.is_available and model_name not in self.available_models:
                continue

            # Check if model matches task specialization
            task_match_score = self._calculate_task_match_score(task_type, model_info)

            suitable_models.append((model_name, model_info, task_match_score))

        if not suitable_models:
            # No suitable models found, use fallback
            logger.warning(f"No suitable models found for task {task_type} with {memory_limit_gb:.1f}GB limit")
            return self.get_safe_fallback()

        # Sort by task match score, then by size (prefer larger for better quality)
        suitable_models.sort(key=lambda x: (x[2], x[1].estimated_ram_gb), reverse=True)

        selected_model = suitable_models[0][0]
        logger.info(f"Selected model {selected_model} for task {task_type}")

        return selected_model

    def _calculate_task_match_score(self, task_type: str, model_info: ModelInfo) -> float:
        """Calculate how well a model matches a task type"""
        score = 0.0

        # Direct specialization match
        if task_type == "code" and "code" in model_info.specialization:
            score += 2.0
        elif task_type == "reasoning" and "reasoning" in model_info.specialization:
            score += 2.0
        elif task_type == "long_context" and "long_context" in model_info.specialization:
            score += 2.0
        elif task_type in ["chat", "standard"] and "chat" in model_info.specialization:
            score += 1.5

        # Context length bonus for long context tasks
        if task_type == "long_context":
            if model_info.context_length >= 16384:
                score += 1.0
            elif model_info.context_length >= 8192:
                score += 0.5

        # General capability score
        if "chat" in model_info.specialization:
            score += 0.5

        return score

    async def validate_model(self, model_name: str) -> tuple[bool, str]:
        """
        Validate that a model works by attempting a small generation.

        Returns:
            (is_valid, error_message)
        """
        if model_name in self.warmup_cache:
            return self.warmup_cache[model_name], ""

        if not self.ollama_client:
            return False, "No Ollama client available"

        try:
            # Try a small test generation
            test_prompt = "Say 'test' and nothing else."
            result = await asyncio.wait_for(
                self.ollama_client.generate(test_prompt, task_type="standard"),
                timeout=10.0
            )

            is_valid = len(result.strip()) > 0
            self.warmup_cache[model_name] = is_valid

            if is_valid:
                self.last_known_good = model_name
                logger.info(f"Model {model_name} validation successful")
            else:
                logger.warning(f"Model {model_name} returned empty response")

            return is_valid, "" if is_valid else "Model returned empty response"

        except asyncio.TimeoutError:
            self.warmup_cache[model_name] = False
            return False, "Model validation timed out"
        except Exception as e:
            self.warmup_cache[model_name] = False
            return False, f"Model validation failed: {e}"

    async def select_and_validate_model(self, task_type: str, resource_profile: ResourceProfile) -> str:
        """
        Select model for task and validate it works.
        Falls back to safe options if selected model fails.
        """
        # First choice: task-specific selection
        selected_model = self.select_model_for_task(task_type, resource_profile)

        # Try to validate the selected model
        is_valid, error = await self.validate_model(selected_model)
        if is_valid:
            return selected_model

        logger.warning(f"Selected model {selected_model} failed validation: {error}")

        # Second choice: last known good model
        if self.last_known_good and self.last_known_good != selected_model:
            is_valid, error = await self.validate_model(self.last_known_good)
            if is_valid:
                logger.info(f"Using last known good model: {self.last_known_good}")
                return self.last_known_good

        # Third choice: safe fallback
        fallback_model = self.get_safe_fallback()
        if fallback_model != selected_model:
            is_valid, error = await self.validate_model(fallback_model)
            if is_valid:
                logger.info(f"Using fallback model: {fallback_model}")
                return fallback_model

        # If all else fails, return the configured model and hope for the best
        logger.error("All model validation attempts failed, using configured model")
        return self.config.model.name

    def get_model_recommendations(self, resource_profile: ResourceProfile) -> List[str]:
        """Get list of recommended models for current resource profile"""
        memory_limit_gb = resource_profile.memory_limit_mb / 1024 if resource_profile.memory_limit_mb else float('inf')

        recommendations = []
        for model_name, model_info in self.MODEL_DATABASE.items():
            if model_info.estimated_ram_gb <= memory_limit_gb:
                recommendations.append(model_name)

        # Sort by size (larger first for better quality)
        recommendations.sort(key=lambda x: self.MODEL_DATABASE[x].estimated_ram_gb, reverse=True)

        return recommendations

    def get_model_info_summary(self) -> str:
        """Get human-readable summary of available models"""
        lines = ["Available Models:"]

        for model_name, model_info in self.MODEL_DATABASE.items():
            availability = "✓" if model_info.is_available else "✗"
            specializations = ", ".join(model_info.specialization)
            lines.append(f"  {availability} {model_name} ({model_info.estimated_ram_gb:.1f}GB, {specializations})")

        return "\n".join(lines)